INSERT INTO t_p42562714_web_app_creation_1.site_content (key, value, description, category)
VALUES (
  'about.page',
  '<h1>О нас</h1><p><strong>ЕРТТП</strong> — это современная онлайн‑платформа, созданная для поддержки и развития местного бизнеса. Мы объединяем производителей, поставщиков и потребителей, формируя устойчивую экосистему региональной торговли.</p><p>Наша цель — сделать локальный рынок более эффективным, прозрачным и доступным для всех участников, создавая конкурентные условия, где главным преимуществом становится качество товаров и услуг.</p><h2>Почему ЕРТТП — ваш надёжный партнёр?</h2><h3>Для предпринимателей:</h3><ul><li><strong>Гарантированные заказы</strong> — заключайте форвардные контракты с чёткими условиями: цена, объём, сроки поставки. Планируйте производство без риска излишков.</li><li><strong>Прямые продажи</strong> — выходите на новых клиентов без посредников, увеличивайте прибыль за счёт сокращения издержек.</li><li><strong>Совместные закупки</strong> — оптимизируйте расходы, объединяясь с другими участниками для выгодных оптовых заказов.</li><li><strong>Простые инструменты</strong> — проводите онлайн‑аукционы, оформляйте договоры в цифровом формате, управляйте процессами в одном окне.</li><li><strong>Репутация — ваш актив</strong> — чем выше ваша оценка и уровень доверия на платформе, тем больше заказов вы получаете.</li></ul><h3>Для потребителей:</h3><ul><li><strong>Широкий ассортимент</strong> — выбирайте из проверенных предложений в ключевых категориях: от продуктов питания до строительных материалов.</li><li><strong>Надёжность поставок</strong> — работайте с проверенными поставщиками, которые выполняют обязательства по форвардным контрактам.</li><li><strong>Выгодные цены</strong> — получайте доступ к оптовым условиям через совместные закупки и прямые поставки.</li><li><strong>Осознанный выбор</strong> — ориентируйтесь на рейтинги и отзывы других пользователей.</li></ul><h2>Что вы найдёте на ЕРТТП?</h2><p>Мы охватываем важнейшие сегменты региональной экономики:</p><ul><li>сельхозпродукция местного производства;</li><li>продукты и товары первой необходимости;</li><li>строительные материалы;</li><li>энергетические и почвенно‑земельные ресурсы;</li><li>транспортные услуги.</li></ul><h2>Наши преимущества для региональной экономики</h2><p><strong>ЕРТТП — это:</strong></p><ul><li><strong>Стабильность для бизнеса</strong> — форвардные контракты обеспечивают предсказуемость доходов и расходов.</li><li><strong>Развитие локального рынка</strong> — деньги остаются в регионе, поддерживая местные предприятия и создавая рабочие места.</li><li><strong>Прозрачность сделок</strong> — все операции фиксируются в системе, минимизируя риски.</li><li><strong>Упрощение торговли</strong> — цифровые инструменты делают процессы максимально удобными.</li><li><strong>Система репутации</strong> — мы стимулируем добросовестную работу: участники с высоким рейтингом получают приоритетное размещение.</li><li><strong>Честная конкуренция</strong> — на платформе создаются равные условия для всех.</li></ul><h2>Начните работать с ЕРТТП уже сегодня!</h2><p>Зарегистрируйтесь на платформе, чтобы расширить клиентскую базу, оптимизировать процессы и укрепить позиции на региональном рынке.</p><p><strong>Важно: участие в платформе полностью бесплатно — никаких скрытых платежей или абонентских взносов.</strong></p>',
  'Полный HTML-текст страницы «О нас» (редактируется через rich-text редактор)',
  'about'
)
